(function(){
  'use strict';
  var cfg = window.VH360ConsentConfig || {}; var state = cfg.state || {choices:{necessary:true,preferences:true,analytics:true,advertising:true},mode:'disabled'}; var memory = {}; var keys = {};
  function has(cat){ if(cat==='necessary') return true; if((navigator.globalPrivacyControl===true || state.gpc) && cat==='advertising') return false; return !!(state.choices && state.choices[cat]); }
  function save(choices, notice){ var fd = new FormData(); fd.append('action','vh360_save_consent'); fd.append('nonce',cfg.nonce||''); fd.append('notice_acknowledged',notice?'1':'0'); ['preferences','analytics','advertising'].forEach(function(c){ fd.append('choices['+c+']', choices[c]?'1':'0'); }); return fetch(cfg.ajaxUrl,{method:'POST',credentials:'same-origin',body:fd}).then(function(r){return r.json();}).then(function(res){ if(res && res.success){ state=res.data; cleanup(); fire(); } return state; }); }
  function fire(){ loadActivityAds(); document.dispatchEvent(new CustomEvent('vh360:consent-changed',{detail:state})); activateScripts(); }
  function cleanup(){ if(has('preferences')) return; Object.keys(keys).forEach(function(k){ try{ localStorage.removeItem(k); }catch(e){} }); }
  function openPrefs(){ var m=document.querySelector('.vh360-consent-modal'); if(!m) return; updateUi(); window.__vh360ConsentFocus=document.activeElement; m.hidden=false; document.documentElement.classList.add('vh360-consent-modal-open'); var f=m.querySelector('button,input,a'); if(f) f.focus(); }
  function closePrefs(){ var m=document.querySelector('.vh360-consent-modal'); if(m) m.hidden=true; document.documentElement.classList.remove('vh360-consent-modal-open'); if(window.__vh360ConsentFocus) window.__vh360ConsentFocus.focus(); }
  function updateUi(){ document.querySelectorAll('[data-vh360-consent-category]').forEach(function(i){ i.checked=has(i.getAttribute('data-vh360-consent-category')); if(i.getAttribute('data-vh360-consent-category')==='advertising' && navigator.globalPrivacyControl===true) i.disabled=true; }); document.querySelectorAll('.vh360-consent-gpc').forEach(function(e){ e.hidden = !(navigator.globalPrivacyControl===true || state.gpc); }); }

  function loadActivityAds(){ if(!api.hasService('activity-feed-ad-slot')) return; document.querySelectorAll('[data-vh360-activity-ad-blocked]').forEach(function(slot){ if(slot.dataset.vh360Loaded) return; slot.dataset.vh360Loaded='1'; var fd=new FormData(); fd.append('action','vh360_activity_ad_markup'); fd.append('nonce',cfg.activityAdNonce||''); fetch(cfg.ajaxUrl,{method:'POST',credentials:'same-origin',body:fd}).then(function(r){return r.json();}).then(function(res){ if(!res||!res.success||!res.data||!res.data.html) return; var wrap=document.createElement('div'); wrap.innerHTML=res.data.html; slot.replaceChildren.apply(slot, Array.prototype.slice.call(wrap.childNodes)); slot.querySelectorAll('script').forEach(function(old){ var n=document.createElement('script'); Array.prototype.slice.call(old.attributes).forEach(function(a){ n.setAttribute(a.name,a.value); }); n.text=old.text||old.textContent; old.parentNode.replaceChild(n, old); }); }); }); }
  function activateScripts(){ document.querySelectorAll('script[type="text/plain"][data-vh360-consent-category],script[type="text/plain"][data-vh360-consent-service]').forEach(function(s){ if(s.dataset.vh360Activated) return; var ok=s.dataset.vh360ConsentService ? api.hasService(s.dataset.vh360ConsentService) : has(s.dataset.vh360ConsentCategory); if(!ok) return; var n=document.createElement('script'); Array.prototype.slice.call(s.attributes).forEach(function(a){ if(a.name.indexOf('data-vh360')!==0 && a.name!=='type') n.setAttribute(a.name,a.value); }); if(s.dataset.vh360Src) n.src=s.dataset.vh360Src; n.text=s.text || s.textContent; s.dataset.vh360Activated='1'; s.parentNode.insertBefore(n,s.nextSibling); }); }
  var api = window.VH360Consent = { has:has, hasService:function(slug){ var svc=(cfg.services||{})[slug]; return svc ? has(svc.category) : true; }, getState:function(){ return state; }, openPreferences:openPrefs, savePreferences:function(c){ return save(c,false); } };
  window.VH360Storage = { registerPreferenceKey:function(k){ if(k) keys[k]=true; }, getPreference:function(k,d){ keys[k]=true; if(has('preferences')){ try{ var v=localStorage.getItem(k); return v===null?d:v; }catch(e){} } return Object.prototype.hasOwnProperty.call(memory,k)?memory[k]:d; }, setPreference:function(k,v){ keys[k]=true; memory[k]=v; if(has('preferences')) try{ localStorage.setItem(k,v); }catch(e){} }, removePreference:function(k){ keys[k]=true; delete memory[k]; try{ localStorage.removeItem(k); }catch(e){} } };
  document.addEventListener('click',function(e){ var t=e.target.closest && e.target.closest('[data-vh360-consent-action],.vh360-consent-open,.vh360-consent-close,.vh360-consent-modal-close'); if(!t) return; if(t.classList.contains('vh360-consent-open')||t.dataset.vh360ConsentAction==='manage'){ e.preventDefault(); openPrefs(); } if(t.classList.contains('vh360-consent-close')){ e.preventDefault(); document.querySelectorAll('[data-vh360-consent-root]').forEach(function(r){r.hidden=true;}); } if(t.classList.contains('vh360-consent-modal-close')){ e.preventDefault(); closePrefs(); } if(t.dataset.vh360ConsentAction==='accept-all'){ e.preventDefault(); save({preferences:true,analytics:true,advertising:!(navigator.globalPrivacyControl===true)},true).then(function(){ document.querySelectorAll('[data-vh360-consent-root]').forEach(function(r){r.hidden=true;}); }); } if(t.dataset.vh360ConsentAction==='reject-optional'){ e.preventDefault(); save({preferences:false,analytics:false,advertising:false},true).then(function(){ document.querySelectorAll('[data-vh360-consent-root]').forEach(function(r){r.hidden=true;}); }); } if(t.dataset.vh360ConsentAction==='save'){ e.preventDefault(); var c={}; document.querySelectorAll('[data-vh360-consent-category]').forEach(function(i){ c[i.getAttribute('data-vh360-consent-category')]=i.checked; }); save(c,true).then(closePrefs); } });
  document.addEventListener('keydown',function(e){ if(e.key==='Escape') closePrefs(); });
  document.addEventListener('DOMContentLoaded',function(){ ['vh360_members_view','vh360_recent_emojis','vh360_quality_prefs','vh360-layout-view-preference','vh360StudioMode'].forEach(window.VH360Storage.registerPreferenceKey); if(state.needs_choice) document.querySelectorAll('[data-vh360-consent-root]').forEach(function(r){r.hidden=false;}); updateUi(); loadActivityAds(); activateScripts(); });
})();
